mapper.select:
SELECT id FROM asset_db.biz_project
WHERE is_deleted = 0
  AND manager_id = #{userId}

SELECT DISTINCT p.id
FROM asset_db.biz_project p
/* 用户角色 */
JOIN asset_db.sys_user_role ur  ON ur.user_id = #{userId}
JOIN asset_db.sys_role r        ON r.id = ur.role_id AND r.is_deleted = 0
/* 自定义数据权限（dataScope=2）的角色关联的部门 */
LEFT JOIN asset_db.sys_role_data rd ON rd.role_id = r.id AND r.data_scope = 2
WHERE p.is_deleted = 0
  AND (
        /* 策略1：用户是项目负责人 */
        p.manager_id = #{userId}
        /* 策略2：用户有自定义部门权限（扩展：若 biz_project 加 dept_id 后启用） */
        /* OR p.dept_id IN (SELECT dept_id FROM sys_role_data WHERE role_id IN (...)) */
      )
